# --- Field-Level Permission Helpers ---

# Private fields that require authorization
PRIVATE_USER_FIELDS = {"email", "phone", "address"}


def can_view_private_field(current_user: Optional[User], target_user_id: str, field_name: str) -> bool:
    """
    Determine if the current user can view a private field of the target user.
    Rules:
    - Admins can see all fields of all users
    - Users can see their own private fields
    - No one else can see private fields
    """
    if current_user is None:
        return False
    if current_user.role == "admin":
        return True
    if current_user.id == target_user_id:
        return True
    return False


def redact_field(current_user: Optional[User], target_user_id: str, field_name: str, value: Any) -> Any:
    """Return the value if authorized, otherwise None."""
    if field_name not in PRIVATE_USER_FIELDS:
        return value
    if can_view_private_field(current_user, target_user_id, field_name):
        return value
    return None


# --- Query Resolvers ---

query = QueryType()


@query.field("me")
def resolve_me(_, info):
    current_user = info.context.get("current_user")
    if current_user is None:
        raise Exception("Authentication required")
    return current_user


@query.field("user")
def resolve_user(_, info, id):
    user = USERS_DB.get(id)
    if user is None:
        raise Exception(f"User with id '{id}' not found")
    return user


@query.field("users")
def resolve_users(_, info, limit=10, offset=0):
    # Enforce max limit to prevent abuse
    limit = min(limit, 100)
    offset = max(offset, 0)

    all_users = list(USERS_DB.values())
    total_count = len(all_users)
    items = all_users[offset: offset + limit]
    return {"items": items, "total_count": total_count}


@query.field("post")
def resolve_post(_, info, id):
    post = POSTS_DB.get(id)
    if post is None:
        raise Exception(f"Post with id '{id}' not found")

    current_user = info.context.get("current_user")

    # Unpublished posts are only visible to the author or admins
    if not post.is_published:
        if current_user is None:
            raise Exception("Post not found")
        if current_user.role != "admin" and current_user.id != post.author_id:
            raise Exception("Post not found")

    return post


@query.field("posts")
def resolve_posts(_, info, authorId=None, limit=10, offset=0):
    limit = min(limit, 100)
    offset = max(offset, 0)

    current_user = info.context.get("current_user")

    filtered_posts = []
    for post in POSTS_DB.values():
        # Filter by author if specified
        if authorId and post.author_id != authorId:
            continue

        # Only show published posts unless the viewer is the author or admin
        if not post.is_published:
            if current_user is None:
                continue
            if current_user.role != "admin" and current_user.id != post.author_id:
                continue

        filtered_posts.append(post)

    total_count = len(filtered_posts)
    items = filtered_posts[offset: offset + limit]
    return {"items": items, "total_count": total_count}


