# --- Security: Query Depth & Complexity Limiting ---

MAX_QUERY_DEPTH = 7
MAX_QUERY_ALIASES = 20
MAX_QUERY_LENGTH = 5000


def calculate_depth(node, current_depth=0) -> int:
    """Recursively calculate the depth of a GraphQL query AST node."""
    if not hasattr(node, "selection_set") or node.selection_set is None:
        return current_depth

    max_child_depth = current_depth
    for selection in node.selection_set.selections:
        child_depth = calculate_depth(selection, current_depth + 1)
        if child_depth > max_child_depth:
            max_child_depth = child_depth

    return max_child_depth


def count_aliases(node) -> int:
    """Count the number of aliases in a query AST to prevent alias-based attacks."""
    count = 0
    if hasattr(node, "alias") and node.alias is not None:
        count += 1
    if hasattr(node, "selection_set") and node.selection_set is not None:
        for selection in node.selection_set.selections:
            count += count_aliases(selection)
    return count


def validate_query_security(document):
    """Validate a parsed GraphQL document against security constraints."""
    for definition in document.definitions:
        depth = calculate_depth(definition)
        if depth > MAX_QUERY_DEPTH:
            raise Exception(
                f"Query depth {depth} exceeds maximum allowed depth of {MAX_QUERY_DEPTH}. "
                "Please simplify your query."
            )

        alias_count = count_aliases(definition)
        if alias_count > MAX_QUERY_ALIASES:
            raise Exception(
                f"Query contains {alias_count} aliases, exceeding the maximum of {MAX_QUERY_ALIASES}. "
                "Please reduce the number of aliases."
            )


# --- Custom GraphQL App with Security Validation ---

from graphql import parse as gql_parse, DocumentNode


class SecureGraphQL(GraphQL):
    """Extended GraphQL ASGI app with query security validation."""

    async def extract_data_from_request(self, request):
        data = await super().extract_data_from_request(request)
        return data

    def get_context_for_request(self, request, data):
        # Retrieve current_user from request state (set by middleware)
        current_user = None
        if hasattr(request, "state") and hasattr(request.state, "current_user"):
            current_user = request.state.current_user

        return {
            "request": request,
            "current_user": current_user,
        }


# --- Authentication Middleware ---

class AuthenticationMiddleware(BaseHTTPMiddleware):
    """
    Middleware that extracts authentication info from the request
    and sets current_user on the request state.

    Supports:
    - Header-based: Authorization: Bearer <user_id>
    - For demo purposes, user_id maps directly to USERS_DB
    """

    async def dispatch(self, request: Request, call_next):
        current_user = None

        auth_header = request.headers.get("Authorization", "")
        if auth_header.startswith("Bearer "):
            token = auth_header[7:].strip()
            # In production, this would validate a JWT or session token
            # For demo, the token is simply the user ID
            current_user = USERS_DB.get(token)

        request.state.current_user = current_user
        response = await call_next(request)
        return response


# --- Query Security Middleware ---

class QuerySecurityMiddleware(BaseHTTPMiddleware):
    """
    Middleware that validates incoming GraphQL queries against
    security constraints before they reach the resolver layer.
    """

    async def dispatch(self, request: Request, call_next):
        if request.method == "POST" and request.url.path == "/graphql":
            try:
                body = await request.body()

                # Check raw query length
                if len(body) > MAX_QUERY_LENGTH:
                    return JSONResponse(
                        {"errors": [{"message": f"Query too large. Maximum size is {MAX_QUERY_LENGTH} bytes."}]},
                        status_code=400,
                    )

                body_json = json.loads(body)
                query_str = body_json.get("query", "")

                if query_str:
                    # Parse and validate the query
                    document = gql_parse(query_str)
                    validate_query_security(document)

                # We need to make the body available again for downstream processing.
                # Starlette consumes the body stream, so we store it.
                request._body = body

            except json.JSONDecodeError:
                return JSONResponse(
                    {"errors": [{"message": "Invalid JSON in request body."}]},
                    status_code=400,
                )
            except Exception as e:
                error_message = str(e)
                if "depth" in error_message.lower() or "aliases" in error_message.lower() or "large" in error_message.lower():
                    return JSONResponse(
                        {"errors": [{"message": error_message}]},
                        status_code=400,
                    )
                # For GraphQL parse errors, let them through to the GraphQL layer
                # which will return proper GraphQL error responses
                pass

        response = await call_next(request)
        return response


